    "featuredImage": "https://prod-files-secure.s3.us-west-2.amazonaws.com/54ac126c-bd77-4cba-8db4-61b14b1ec687/5d6185e5-62df-4827-9921-c6a9e4ed4dad/u2556576747_A_modern_minimalistic_cover_image_for_an_article__804bf000-733a-4088-9c41-fa4ff4fce7df_3.png?X-Amz-Algorithm=AWS4-HMAC-SHA256&X-Amz-Content-Sha256=UNSIGNED-PAYLOAD&X-Amz-Credential=ASIAZI2LB4663Q3UEE2G%2F20260211%2Fus-west-2%2Fs3%2Faws4_request&X-Amz-Date=20260211T085308Z&X-Amz-Expires=3600&X-Amz-Security-Token=IQoJb3JpZ2luX2VjEPH%2F%2F%2F%2F%2F%2F%2F%2F%2F%2FwEaCXVzLXdlc3QtMiJHMEUCIFMj7HUyVs%2BsU9txr74zIUmoFiZ5yJ3RB6N5HkeSe0tEAiEAz9n%2FRc6bekBnDaILLEFefsoM6PVVNLydTr4hn7dAwMwqiAQIuv%2F%2F%2F%2F%2F%2F%2F%2F%2F%2FARAAGgw2Mzc0MjMxODM4MDUiDBQNxr59Yreglff5ISrcAzfD59RBn3T0egJptZyndWgK8QHeL008GLtKik9FsOXwlx14we7H80ABohqr%2B0MD2zNKhfo4frylNPRhpqZIsQrZIuTi9I20x12rcmY80rkeT5q5N8ta32FcUtV1tRQw5IPL7JB8jG%2FT7%2FqUyCLPBCOWkeQDte6dlZOjxnYw6REoZAImDZKUI1gv5cZRy35lQw49Bey3P7b8mclbz8LcCXCe6l%2F3zGUdbWpRhtzSTJp5gmZcaMehN4A7w90pKiwIX2cf95W2bup0km0f5MgChcQMR7tA99aHvJk0%2FKppojRBo7Vvcwiyipz5SztappvgzpvqVLzbQ7qsWKW4kKc953pecI8xfow54qvnq1nDXyHC%2FCi1QJ6NDZ2gG4IsgZj%2BX1Otx9Zrj3v91jMdp%2BHqpIATfZjQYAd8R5ablzDuSzKxBB%2BzdOdKCNEXrJb9WmjMaTV4%2FFN3jwqp%2Fe8i57wUKK8Cw3yqdgPAKHCYhYjMYpiwLf00tSaIHk2GPMbdtya0s1EjelyE8adsxvlF1r68UpD%2FOCTEpK13EQwskDPSx%2BAXGuc9vq83jVbhOkukRjVxqY3wmc1jFNZNKhwts8G397KUGmXXvhYTsZhwDmbJpLZwFvQxFVPLHGM7MLWEMPn9sMwGOqUBjNorwT8sgSxb0ZBE67DF038NCRHu35NbQ48Nm%2FHnphizveCvbhM8u9gHdO3dhpCadM6PR80fXNIpw3fF3NHOWQGYv3m0%2B%2B4h9nOAW75DirDglRB1R13dE6XXDvG%2FVm%2BLi5XbunbKmvxzrZP%2Fdl30rjE44TPovC0jrh3eRXI6NykOMfhKHiS1KUaye5g61dG7m7vigw%2FJOx9bEvSdHiS0f4qNJQAC&X-Amz-Signature=4ad57f23dcd4cdcfd6470042e9a90a880087d63a3a9618bb8507df1aad8c26ff&X-Amz-SignedHeaders=host&x-amz-checksum-mode=ENABLED&x-id=GetObject"
